package com.careeros.provider.application;import com.careeros.provider.domain.*;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service @Transactional public class SyncHistoryService{private final SyncHistoryRepository r;public SyncHistoryService(SyncHistoryRepository r){this.r=r;}public SyncHistory record(SyncHistory h){return r.save(h);}@Transactional(readOnly=true)public Page<SyncHistory>list(Pageable p){return r.findAll(p);}@Transactional(readOnly=true)public Page<SyncHistory>company(UUID id,Pageable p){return r.findByCompanyId(id,p);}@Transactional(readOnly=true)public Page<SyncHistory>provider(ProviderType t,Pageable p){return r.findByProvider(t,p);}@Transactional(readOnly=true)public List<SyncHistory>all(){return r.findAll();}}
